class PaymentProcessingError(Exception):
    """Custom exception for payment processing errors."""
    pass


def verify_signature(payload: bytes, secret: str, signature: str) -> bool:
    """Verify the webhook signature using HMAC-SHA256."""
    try:
        expected_signature = hmac.new(
            secret.encode("utf-8"),
            payload,
            hashlib.sha256
        ).hexdigest()

        return hmac.compare_digest(expected_signature, signature)
    except Exception as e:
        logging.error(f"Signature verification error: {str(e)}")
        return False


def process_payment_event(
    event_type: str,
    transaction_id: str,
    amount: float,
    currency: str,
    payment_status: str,
    provider: str,
    metadata: dict
) -> dict:
    """Process different types of payment events."""

    valid_event_types = [
        "payment.completed",
        "payment.failed",
        "payment.pending",
        "payment.refunded",
        "payment.cancelled",
        "payment.disputed",
        "subscription.created",
        "subscription.cancelled",
        "subscription.renewed"
    ]

    if event_type not in valid_event_types:
        raise PaymentProcessingError(f"Unknown event type: {event_type}")

    valid_statuses = ["success", "failed", "pending", "refunded", "cancelled", "disputed"]
    if payment_status not in valid_statuses:
        raise PaymentProcessingError(f"Invalid payment status: {payment_status}")

    if not isinstance(amount, (int, float)) or amount < 0:
        raise PaymentProcessingError(f"Invalid amount: {amount}")

    result = {
        "event_type": event_type,
        "action_taken": None
    }

    if event_type == "payment.completed":
        result["action_taken"] = "order_fulfilled"
        logging.info(f"Payment completed for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "payment.failed":
        result["action_taken"] = "customer_notified"
        logging.warning(f"Payment failed for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "payment.pending":
        result["action_taken"] = "awaiting_confirmation"
        logging.info(f"Payment pending for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "payment.refunded":
        result["action_taken"] = "refund_processed"
        logging.info(f"Payment refunded for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "payment.cancelled":
        result["action_taken"] = "order_cancelled"
        logging.info(f"Payment cancelled for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "payment.disputed":
        result["action_taken"] = "dispute_review_initiated"
        logging.warning(f"Payment disputed for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "subscription.created":
        result["action_taken"] = "subscription_activated"
        logging.info(f"Subscription created for transaction {transaction_id}: {amount} {currency}")

    elif event_type == "subscription.cancelled":
        result["action_taken"] = "subscription_deactivated"
        logging.info(f"Subscription cancelled for transaction {transaction_id}")

    elif event_type == "subscription.renewed":
        result["action_taken"] = "subscription_extended"
        logging.info(f"Subscription renewed for transaction {transaction_id}: {amount} {currency}")

    # Here you would typically:
    # 1. Store the event in a database (e.g., Azure Cosmos DB, Azure SQL)
    # 2. Update order/subscription status
    # 3. Send notifications via Azure Service Bus or Event Grid
    # 4. Trigger downstream workflows

    return result


